from collections import Counter
from typing import Any, Dict

def count_element_freq(tpl: tuple) -> Dict[Any, int]:
    """Count frequency of elements in a (possibly) nested tuple."""
    freq = Counter()

    def visit(item):
        if isinstance(item, tuple):
            for sub in item:
                visit(sub)
        else:
            freq[item] += 1

    visit(tpl)
    return dict(freq)


# Example / given test
assert count_element_freq((5, 6, (5, 6), 7, (8, 9), 9)) == {5: 2, 6: 2, 7: 1, 8: 1, 9: 2}
