def max_sum_increasing_subsequence(arr, n):
    # Edge case: empty array
    if n == 0:
        return 0

    # dp[i] will store the maximum sum of an increasing subsequence ending at index i
    dp = arr[:]  # each element alone forms an increasing subsequence

    for i in range(1, n):
        for j in range(i):
            if arr[j] < arr[i]:
                dp[i] = max(dp[i], dp[j] + arr[i])

