```python
def search_literal(pattern: str, text: str):
    """
    Return (start, end) indices of first occurrence of pattern in text.
    If not found, return (-1, -1).
    end is a non-inclusive index.
    """
    if pattern == "":
        # Convention: empty pattern found at position 0
        return (0, 0)

    start = text.find(pattern)
    if start == -1:
        return (-1, -1)

    end = start + len(pattern)
    return (start, end)

# Example / given test
assert search_literal('python', 'python programming language') == (0, 6)
```

