{"code": "def assign_elements(pairs):
    # Build for each element: list of all its direct pair partners in order
    partners = {}
    for a, b in pairs:
        partners.setdefault(a, []).append(b)
        partners.setdefault(b, []).append(a)
    # For each element, collect partners that originate from other pairs
    result = {key: [] for key in partners}
    for x in partners:
        seen = set()
        res_list = []
        for a, b in pairs:
            if x == a:
                # partner from its own pair, skip
                continue
            if x == b:
                # partner from its own pair, skip
                continue
            # if x appears as a partner with `a` or `b` elsewhere, add that partner
            if x in partners.get(a, []) and a not in seen:
                seen.add(a)
                res_list.append(a)
            if x in partners.get(b, []) and b not in seen:
                seen.add(b)
                res_list.append(b)
