def extract_even(data):
    """Recursively extract even integers from a nested tuple structure."""
    # Base case: if it's an integer, return it if even, else None
    if isinstance(data, int):
        return data if data % 2 == 0 else None

    # If it's a tuple, process each element
    if isinstance(data, tuple):
        result = []
        for elem in data:
